  ('locality-814ced5a-moex-00076', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '小花與小美為同性伴侶，相戀五年後決定締結法律上的伴侶關係。請問依據我國相關法律，下列何者 正確？', '["小美與小花的父母為直系姻親", "小美與小花互為日常家務代理人", "兩人須滿20歲為完全行為能力人，方可締結法律上的伴侶關係", "同性伴侶不屬婚姻關係，故小花仍可與其他異性結婚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00077', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '關於憲法訴訟法，下列敘述何者正確？', '["大法官透過大法官會議作成憲法解釋", "法規範違憲侵害人民權益時，人民得逕行聲請釋憲", "立法委員就其行使職權認為法律有牴觸憲法時，得逕行聲請釋憲", "司法院大法官以判決宣告牴觸憲法之法律失效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00078', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '某男子A每天至女友B住處接送她上班，卻常因看見B與他人有說有笑而多次毆打她，B決定依據 家庭暴力防治法維護自身權益，下列分析何者正確？', '["被害人可自行向法院聲請緊急保護令", "法院可不經審理程序直接核發暫時保護令", "因兩人未同居因此無法適用家庭暴力防治法", "若被害人有受家暴急迫危險者可請社會局先核發保護令"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00079', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '董氏基金會長年致力於菸害之防治，請問對於該組織屬性之描述，下列何者正確？', '["社團法人", "公法人", "財團法人", "第二部門"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00080', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '憲法第23條要求限制人民基本權利時，必須以法律為之，此為我國法律保留原則的重要體現。關於 法律保留原則，下列敘述何者正確？', '["立法者以法律授權特定行政機關訂定行政命令時，該機關不得再將該授權轉交其他機關，使其訂定 行政命令", "給付行政並非限制人民基本權利，因此無法律保留原則的適用餘地", "倘若立法院因專業能力侷限，得決議直接放棄立法，委託行政機關制定命令以限制人民權利", "限制人民基本權利之法律規範必須明確，不得使用不確定法律概念"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00081', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '若法官於審理案件時，認為行政機關所訂定之法規命令，其內容已明顯逾越母法規範，依法得為何種 處置？', '["法官得於個案審理中拒絕適用，並宣告該法規命令於判決後正式失效", "法官得停止審理，要求行政機關重新訂定法規命令", "法官得直接宣告該法規命令因違法而自始無效", "法官僅得於個案審理中拒絕適用，但該法規命令之效力不受影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00082', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '某學校行政單位針對同一樣態學生考試違規，部分學生依規定懲處，部分未懲處。該單位之行為違反 何種行政法原則？', '["比例原則", "平等原則", "明確性原則", "裁量合法適宜原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00083', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '教育可培育優秀的人力資源，也是社會進步與發展的原動力，教育也常被認為會造成外部效益，所以 政府應該採取下列那一措施？', '["允許更多大學設立", "提高學費", "推動母語教學", "補貼教育"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00084', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '2020年新冠肺炎疫情重創旅遊市場，交通部觀光局推出安心旅遊補助，至同年10月底，政府補貼逾 新臺幣82億元，此項政府支出類型與下列何者相同？', '["因應新課程教法新增的人事費", "中央政府編列的債務利息支出", "興建桃園大眾捷運系統的預算", "縣市鼓勵生育發放的生育津貼"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00085', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '假設其他條件不變。當利率上升時，下列敘述何者正確？', '["股票價格與債券交易價格都會上漲", "股票價格與債券交易價格都會下跌", "股票價格會上漲，債券交易價格會下跌", "股票價格會下跌，債券交易價格會上漲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
